import React, { useEffect, useState } from "react";
import { Box, Typography, Paper } from "@mui/material";
import {
  getDatabase,
  ref,
  onValue,
} from "https://www.gstatic.com/firebasejs/10.11.1/firebase-database.js";
import { db } from "./firebase";

const Stats = () => {
  const [stats, setStats] = useState({});

  useEffect(() => {
    const usersRef = ref(db, "users");

    onValue(usersRef, (snapshot) => {
      const data = snapshot.val();

      if (!data) return;

      const result = {};

      Object.values(data).forEach((userAnswers) => {
        Object.entries(userAnswers).forEach(([questionKey, answer]) => {
          const answerValue =
            typeof answer === "string" ? answer : answer?.title;

          if (!result[questionKey]) {
            result[questionKey] = {};
          }

          if (!result[questionKey][answerValue]) {
            result[questionKey][answerValue] = 0;
          }

          result[questionKey][answerValue] += 1;
        });
      });

      setStats(result);
    });
  }, []);

  return (
    <Box p={3}>
      <Typography variant="h4" mb={3}>
        İstatistikler
      </Typography>

      {Object.entries(stats).map(([questionKey, answers]) => (
        <Paper key={questionKey} sx={{ p: 2, mb: 3 }}>
          <Typography variant="h6" mb={2}>
            Soru: {questionKey}
          </Typography>

          {Object.entries(answers)
            .sort((a, b) => b[1] - a[1]) // 🔥 en çok oy alan üstte
            .map(([answer, count]) => (
              <Box
                key={answer}
                sx={{
                  mb: 1,
                  p: 1,
                  borderBottom: "1px solid #ccc",
                }}
              >
                <Typography variant="body1">
                  {answer} → {count} oy
                </Typography>
              </Box>
            ))}
        </Paper>
      ))}
    </Box>
  );
};

export default Stats;
